import React, { useState, useEffect, useRef } from 'react';
import { 
  AppStep, ReportData, ReportSection, ReportConfig, ReportTheme, 
  WatermarkPosition, ProjectType,
  ExportSettings, PageSize, PageMargins, BlendMode, ImageAspectRatio 
} from './types';
import { saveToArchive, getArchive, deleteFromArchive } from './services/storageService';
import { exportToPPTX } from './services/pptxService';
import { exportToPDF } from './services/pdfService';
import { polishContent, analyzeImage } from './services/geminiService';
import ZanaLoader from './components/ZanaLoader';

const APP_LOGO_URL = "https://i.imgur.com/qwcpmNU.png";

const DEFAULT_THEME: ReportTheme = {
  primaryColor: '#2563eb',
  secondaryColor: '#1e293b',
  fontFamily: 'Inter',
  accentShape: 'geometric',
  layoutStyle: 'modern',
  watermarkText: 'CONFIDENTIAL ARCHIVE',
  watermarkOpacity: 0.05,
  watermarkSize: 6,
  watermarkColor: '#000000',
  showGlobalWatermark: true,
  logoUrl: '',
  logoOpacity: 0.4,
  logoScale: 150,
  logoPosition: 'top-left',
  logoRotation: 0,
  logoBlendMode: 'multiply'
};

const FONT_OPTIONS = [
  'Inter', 'IBM Plex Sans Arabic', 'Montserrat', 'Playfair Display', 'Lexend', 'Space Grotesk', 'Outfit', 'Cormorant Garamond', 'Syne', 'Plus Jakarta Sans', 'Fira Code', 'Roboto', 'Arial', 'Times New Roman'
];

const ASPECT_RATIOS: ImageAspectRatio[] = ['16:9', '4:3', '1:1', '9:16', '21:9', 'auto'];

const THEME_PRESETS: { name: string, theme: Partial<ReportTheme> }[] = [
  { name: 'Particle Flow', theme: { layoutStyle: 'particle_flow', primaryColor: '#8b5cf6', secondaryColor: '#4c1d95', fontFamily: 'Syne' } },
  { name: 'Star System', theme: { layoutStyle: 'star_system', primaryColor: '#fde047', secondaryColor: '#1e293b', fontFamily: 'Space Grotesk' } },
  { name: 'Blueprint Plus', theme: { layoutStyle: 'blueprint_plus', primaryColor: '#2563eb', secondaryColor: '#1d4ed8', fontFamily: 'Fira Code' } },
  { name: 'Parametric Hadid', theme: { layoutStyle: 'parametric', primaryColor: '#6366f1', secondaryColor: '#312e81', fontFamily: 'Space Grotesk' } },
  { name: 'Editorial Vogue', theme: { layoutStyle: 'editorial', primaryColor: '#000000', secondaryColor: '#4a4a4a', fontFamily: 'Playfair Display' } },
  { name: 'Cyber Technical', theme: { layoutStyle: 'cyber', primaryColor: '#22d3ee', secondaryColor: '#083344', fontFamily: 'Fira Code' } },
  { name: 'Bauhaus Master', theme: { layoutStyle: 'bauhaus', primaryColor: '#e11d48', secondaryColor: '#4c0519', fontFamily: 'Montserrat' } },
  { name: 'Brutalist Raw', theme: { layoutStyle: 'brutalist', primaryColor: '#000000', secondaryColor: '#171717', fontFamily: 'Inter' } },
  { name: 'Zen Architecture', theme: { layoutStyle: 'zen', primaryColor: '#059669', secondaryColor: '#064e3b', fontFamily: 'Cormorant Garamond' } },
  { name: 'Modern Pro', theme: { layoutStyle: 'modern', primaryColor: '#2563eb', secondaryColor: '#1e293b', fontFamily: 'Inter' } },
];

const POSITIONS: WatermarkPosition[] = ['top-left', 'top-right', 'bottom-left', 'bottom-right', 'center'];

const stripHtml = (html: string) => {
  const doc = new DOMParser().parseFromString(html, 'text/html');
  return doc.body.textContent || "";
};

/**
 * Professional Rich Text Toolbar.
 * Optimized for both desktop (floating) and mobile (docked).
 * Includes new requested formatting options: Strikethrough, Superscript, Subscript.
 */
const ProToolbar: React.FC<{ 
  position: { x: number, y: number } | null, 
  onClose: () => void 
}> = ({ position }) => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [showColorPicker, setShowColorPicker] = useState(false);

  useEffect(() => {
    const checkSize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', checkSize);
    return () => window.removeEventListener('resize', checkSize);
  }, []);

  const apply = (cmd: string, val?: string) => {
    document.execCommand(cmd, false, val);
    const active = document.activeElement;
    if (active && active.hasAttribute('contenteditable')) {
      active.dispatchEvent(new Event('input', { bubbles: true }));
    }
    // Close pickers after applying
    if (cmd === 'foreColor') setShowColorPicker(false);
  };

  const handleInsertImage = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (event) => {
          const base64 = event.target?.result as string;
          const imgHtml = `<img src="${base64}" style="max-width: 100%; height: auto; border-radius: 12px; margin: 20px 0; display: block; box-shadow: 0 10px 30px -10px rgba(0,0,0,0.1);" alt="Inserted asset" />`;
          document.execCommand('insertHTML', false, imgHtml);
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const stopFocusLoss = (e: React.MouseEvent) => e.preventDefault();

  // Desktop Floating Style
  const desktopStyle: React.CSSProperties = position ? {
    position: 'fixed',
    top: position.y - 12,
    left: position.x,
    transform: 'translate(-50%, -100%)',
    zIndex: 2000,
  } : { display: 'none' };

  // Mobile Bottom-Docked Style
  const mobileStyle: React.CSSProperties = {
    position: 'fixed',
    bottom: 'env(safe-area-inset-bottom, 0)',
    left: 0,
    right: 0,
    zIndex: 2000,
    borderRadius: '24px 24px 0 0',
  };

  return (
    <div 
      className={`${isMobile ? 'bg-white shadow-[0_-20px_50px_rgba(0,0,0,0.2)] border-t border-slate-100 p-4 mobile-toolbar-slide' : 'bg-white border border-slate-200 shadow-[0_30px_90px_-15px_rgba(0,0,0,0.4)] rounded-2xl p-2 animate-in zoom-in-95 fade-in duration-200 origin-bottom'} flex flex-col items-center justify-center no-print`}
      style={isMobile ? mobileStyle : desktopStyle}
      onMouseDown={stopFocusLoss}
    >
      <div className="flex items-center justify-center space-x-1 overflow-x-auto w-full max-w-full custom-scrollbar">
        {/* Font Family Selection - Enabled for all platforms */}
        <div className={`flex items-center ${isMobile ? 'space-x-2' : 'border-r border-slate-100 pr-3 mr-1'}`}>
          <select 
            onMouseDown={stopFocusLoss}
            onChange={(e) => apply('fontName', e.target.value)}
            className="bg-slate-50 text-[10px] lg:text-[11px] font-bold outline-none cursor-pointer p-1.5 lg:p-2 rounded-xl border border-slate-200 w-20 lg:w-24"
          >
            <option value="">Font</option>
            {FONT_OPTIONS.map(f => <option key={f} value={f}>{f}</option>)}
          </select>
          <select 
            onMouseDown={stopFocusLoss}
            onChange={(e) => apply('fontSize', e.target.value)}
            className="bg-slate-50 text-[10px] lg:text-[11px] font-bold outline-none cursor-pointer p-1.5 lg:p-2 rounded-xl border border-slate-200"
            defaultValue="3"
          >
            <option value="1">Small</option>
            <option value="3">Med</option>
            <option value="5">Large</option>
            <option value="7">Extra</option>
          </select>
        </div>

        {/* Basic Formatting: Bold, Italic, Underline, Strikethrough */}
        <div className={`flex items-center space-x-1 lg:space-x-2 ${!isMobile ? 'border-r border-slate-100 pr-3 mr-1' : ''}`}>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('bold')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 font-black text-sm lg:text-lg" title="Bold">B</button>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('italic')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 italic font-serif text-sm lg:text-lg" title="Italic">I</button>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('underline')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 underline text-sm lg:text-lg" title="Underline">U</button>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('strikeThrough')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 line-through text-xs lg:text-base" title="Strikethrough">S</button>
        </div>

        {/* Script Formatting: Superscript, Subscript */}
        <div className={`flex items-center space-x-1 lg:space-x-2 ${!isMobile ? 'border-r border-slate-100 pr-3 mr-1' : ''}`}>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('superscript')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 text-[10px] lg:text-xs" title="Superscript">x²</button>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('subscript')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 text-[10px] lg:text-xs" title="Subscript">x₂</button>
        </div>

        {/* Alignment & Assets */}
        <div className={`flex items-center space-x-1 lg:space-x-2 ${!isMobile ? 'border-r border-slate-100 pr-3 mr-1' : ''}`}>
          <button onMouseDown={stopFocusLoss} onClick={() => apply('justifyCenter')} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-600" title="Align Center">
            <svg className="w-4 h-4 lg:w-5 lg:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 6h16M7 12h10M4 18h16"></path></svg>
          </button>
          <button onMouseDown={stopFocusLoss} onClick={handleInsertImage} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-blue-600" title="Insert Asset">
            <svg className="w-4 h-4 lg:w-5 lg:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
          </button>
        </div>

        {/* Color Palette Toggle */}
        <div className="relative flex items-center">
          <button 
            onMouseDown={stopFocusLoss} 
            onClick={() => setShowColorPicker(!showColorPicker)}
            className={`w-8 h-8 lg:w-10 lg:h-10 flex flex-col items-center justify-center hover:bg-slate-100 rounded-xl transition-colors ${showColorPicker ? 'bg-blue-50' : ''}`} 
            title="Text Color"
          >
            <span className="text-[10px] lg:text-[12px] font-black text-slate-900 leading-none">A</span>
            <div className="w-3 lg:w-4 h-0.5 bg-red-600 mt-0.5 rounded-full"></div>
          </button>

          {/* Enhanced Color Picker: Click-based for both mobile and desktop */}
          {showColorPicker && (
            <div 
              className={`absolute ${isMobile ? 'bottom-full mb-4 left-1/2 -translate-x-1/2' : 'top-full mt-2 left-1/2 -translate-x-1/2'} grid grid-cols-4 gap-2 p-3 bg-white shadow-2xl rounded-2xl border border-slate-100 z-[2001] w-36`} 
              onMouseDown={stopFocusLoss}
            >
              {['#ef4444', '#22c55e', '#3b82f6', '#000000', '#f59e0b', '#8b5cf6', '#ec4899', '#ffffff'].map(c => (
                <button 
                  key={c} 
                  onMouseDown={stopFocusLoss}
                  onClick={() => apply('foreColor', c)} 
                  className="w-6 h-6 rounded-full border border-slate-200 transition-transform hover:scale-125" 
                  style={{ backgroundColor: c }} 
                />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const ComplianceToggle: React.FC<{ status: boolean | null, onToggle: (s: boolean | null) => void }> = ({ status, onToggle }) => (
  <div className="flex items-center space-x-1 no-print bg-slate-100 p-1.5 rounded-xl">
    <button onClick={() => onToggle(true)} className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase tracking-tighter transition-all ${status === true ? 'bg-green-500 text-white shadow-md' : 'text-slate-400'}`}>T</button>
    <button onClick={() => onToggle(false)} className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase tracking-tighter transition-all ${status === false ? 'bg-red-500 text-white shadow-md' : 'text-slate-400'}`}>F</button>
    <button onClick={() => onToggle(null)} className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase tracking-tighter transition-all ${status === null ? 'bg-slate-300 text-slate-700' : 'text-slate-200'}`}>Ø</button>
  </div>
);

const ComplianceBadge: React.FC<{ status: boolean | null }> = ({ status }) => {
  if (status === null) return null;
  return (
    <div className={`absolute top-8 left-8 z-20 px-4 py-2 rounded-full font-black text-[10px] uppercase tracking-widest shadow-lg border-2 border-white ${status ? 'bg-green-500 text-white' : 'bg-red-500 text-white'}`}>
      {status ? 'Compliant' : 'Non-Compliant'}
    </div>
  );
};

const EditableField = ({ value, onBlur, className, style }: any) => {
  const fieldRef = useRef<HTMLDivElement>(null);
  const isEditing = useRef(false);

  useEffect(() => {
    if (fieldRef.current && !isEditing.current) {
      fieldRef.current.innerHTML = value || '';
    }
  }, [value]);

  if (!onBlur) return <div className={className} style={style} dangerouslySetInnerHTML={{ __html: value }}></div>;

  return (
    <div 
      ref={fieldRef}
      contentEditable 
      suppressContentEditableWarning 
      onFocus={() => { isEditing.current = true; }}
      onBlur={(e) => {
        isEditing.current = false;
        const newHtml = e.currentTarget.innerHTML;
        if (newHtml !== value) {
          onBlur(newHtml);
        }
      }}
      className={`${className} edit-highlight outline-none cursor-text p-1 rounded-sm transition-all focus:bg-blue-50/50 min-h-[1em]`}
      style={style}
    />
  );
};

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.DASHBOARD);
  const [archive, setArchive] = useState<ReportData[]>([]);
  const [currentReport, setCurrentReport] = useState<ReportData | null>(null);
  const [isDesignMode, setIsDesignMode] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(window.innerWidth > 1024);
  const [activeTab, setActiveTab] = useState<'content' | 'theme' | 'watermark'>('content');
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');

  const [toolbarPos, setToolbarPos] = useState<{ x: number, y: number } | null>(null);
  const [isFocused, setIsFocused] = useState(false);

  const [exportSettings, setExportSettings] = useState<ExportSettings>({
    pageSize: 'A4',
    margins: 'normal',
    compression: 'medium',
    includeLogo: true
  });

  const logoInputRef = useRef<HTMLInputElement>(null);
  const autoSaveTimerRef = useRef<number | null>(null);

  useEffect(() => {
    setArchive(getArchive());
    const handleResize = () => {
      if (window.innerWidth <= 1024) setIsSidebarOpen(false);
    };
    window.addEventListener('resize', handleResize);

    const handleSelectionChange = () => {
      if (!isDesignMode) return;
      const selection = window.getSelection();

      const active = document.activeElement;
      const isInsideEditable = active && (active.hasAttribute('contenteditable') || active.closest('[contenteditable]'));
      setIsFocused(!!isInsideEditable);

      if (selection && !selection.isCollapsed) {
        const range = selection.rangeCount > 0 ? selection.getRangeAt(0) : null;
        if (!range) {
          setToolbarPos(null);
          return;
        }

        const container = range.commonAncestorContainer.nodeType === 1 
          ? range.commonAncestorContainer as HTMLElement 
          : range.commonAncestorContainer.parentElement;

        if (container && (container.hasAttribute('contenteditable') || container.closest('[contenteditable]'))) {
          const rect = range.getBoundingClientRect();
          const y = rect.top !== 0 ? rect.top : (container as HTMLElement).getBoundingClientRect().top;
          const x = rect.left !== 0 ? (rect.left + rect.width / 2) : (container as HTMLElement).getBoundingClientRect().left + 50;

          setToolbarPos({
            x: x,
            y: y + window.scrollY
          });
        } else {
           setToolbarPos(null);
        }
      } else {
        if (!isInsideEditable) {
          setToolbarPos(null);
        }
      }
    };

    const handleGlobalMouseUp = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (!target.closest('.edit-highlight') && !target.closest('.no-print')) {
         if (!target.closest('[onMouseDown]')) {
           setToolbarPos(null);
           setIsFocused(false);
         }
      }
    };

    window.addEventListener('mouseup', handleGlobalMouseUp);
    document.addEventListener('selectionchange', handleSelectionChange);

    return () => {
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('mouseup', handleGlobalMouseUp);
      document.removeEventListener('selectionchange', handleSelectionChange);
    };
  }, [isDesignMode]);

  useEffect(() => {
    if (currentReport) {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);
      autoSaveTimerRef.current = window.setTimeout(() => {
        saveToArchive(currentReport);
        setArchive(getArchive());
      }, 1000) as unknown as number; 
    }
  }, [currentReport]);

  const createNewProject = (type: ProjectType) => {
    const newReport: ReportData = {
      config: {
        id: Math.random().toString(36).substr(2, 9),
        topic: type === 'CV' ? 'Curriculum Vitae' : type === 'Seminar' ? 'Professional Presentation' : 'Strategic Identity Report',
        reportFor: 'Internal Stakeholder',
        createdBy: 'Studio Principal',
        date: new Date().toLocaleDateString(),
        projectType: type,
        theme: { ...DEFAULT_THEME, layoutStyle: type === 'CV' ? 'metropolitan' : type === 'Seminar' ? 'onyx' : 'modern' },
        coverLabels: { preparedFor: 'Prepared For', architectPrincipal: 'Studio Principal' }
      },
      sections: [
        { 
          id: Math.random().toString(36).substr(2, 9), 
          title: 'Strategic Overview', 
          content: 'Synthesized professional analysis regarding the structural framework and core identity values of this project.', 
          isChecked: true, order: 1, type: 'intro',
          imageScale: 1, imageAspectRatio: '16:9', contentScale: 1, isCompliant: null,
          imageUrl: '' 
        }
      ]
    };
    setCurrentReport(newReport);
    setStep(AppStep.EDITOR);
  };

  const updateSection = (id: string, updates: Partial<ReportSection>) => {
    if (!currentReport) return;
    setCurrentReport({
      ...currentReport,
      sections: currentReport.sections.map(s => s.id === id ? { ...s, ...updates } : s)
    });
  };

  const updateTheme = (updates: Partial<ReportTheme>) => {
    if (!currentReport) return;
    setCurrentReport({
      ...currentReport,
      config: { ...currentReport.config, theme: { ...currentReport.config.theme, ...updates } }
    });
  };

  const updateConfig = (updates: Partial<ReportConfig>) => {
    if (!currentReport) return;
    setCurrentReport({
      ...currentReport,
      config: { ...currentReport.config, ...updates }
    });
  };

  const handleGeminiPolish = async (sectionId: string) => {
    const section = currentReport?.sections.find(s => s.id === sectionId);
    if (!section) return;
    setIsLoading(true);
    setLoadingMsg("Refining architectural narrative...");
    try {
      const polished = await polishContent(section.content, section.title);
      updateSection(sectionId, { content: polished });
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, sectionId: string) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateSection(sectionId, { imageUrl: base64 });
    };
    reader.readAsDataURL(file);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateTheme({ logoUrl: base64 });
    };
    reader.readAsDataURL(file);
  };

  const handleExportPDF = async () => {
    if (!currentReport) return;
    setIsExportModalOpen(false);
    setIsLoading(true);
    setLoadingMsg("Exporting high-fidelity PDF document...");
    try {
      const timestamp = new Date().toISOString().split('T')[0].replace(/-/g, '');
      const sanitizedName = `${stripHtml(currentReport.config.topic).replace(/\s+/g, '_')}_${timestamp}`;
      await exportToPDF('main-preview-container', sanitizedName, exportSettings);
    } catch (e) {
      console.error(e);
      alert("Export failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleExportPPTX = async () => {
    if (!currentReport) return;
    setIsExportModalOpen(false);
    const timestamp = new Date().toISOString().split('T')[0].replace(/-/g, '');
    const sanitizedName = `${stripHtml(currentReport.config.topic).replace(/\s+/g, '_')}_${timestamp}`;
    await exportToPPTX(currentReport, { ...currentReport.config, topic: sanitizedName });
  };

  const ZanaLogoUI = () => (
    <div className="flex items-center space-x-3">
      <div 
        className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-2xl transform rotate-3 border-2 border-white/20 bg-white overflow-hidden"
      >
        <img src={APP_LOGO_URL} className="w-full h-full object-cover" alt="Zana Logo" />
      </div>
      <div className="flex flex-col">
        <span className="font-black text-slate-900 tracking-tighter text-sm uppercase leading-none">Studio Vault</span>
        <span className="text-[9px] font-bold tracking-widest uppercase opacity-40">Architectural Suite</span>
      </div>
    </div>
  );

  const LogoWatermarkOverlay = ({ theme }: { theme: ReportTheme }) => {
    if (!theme.logoUrl) return null;
    const posStyles: Record<WatermarkPosition, React.CSSProperties> = {
      'top-left': { top: '40px', left: '40px' },
      'top-right': { top: '40px', right: '40px' },
      'bottom-left': { bottom: '40px', left: '40px' },
      'bottom-right': { bottom: '40px', right: '40px' },
      'center': { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' }
    };

    return (
      <div 
        className="logo-watermark-container absolute pointer-events-none z-[60]"
        style={{ 
          ...posStyles[theme.logoPosition], 
          opacity: theme.logoOpacity,
          mixBlendMode: theme.logoBlendMode,
          transform: `${posStyles[theme.logoPosition].transform || ''} rotate(${theme.logoRotation}deg) scale(${theme.logoScale / 150})`
        }}
      >
        <img src={theme.logoUrl} className="max-w-[150px] h-auto" alt="Logo" />
      </div>
    );
  };

  const WatermarkStamp = ({ theme, isDarkTheme }: { theme: ReportTheme, isDarkTheme: boolean }) => {
    if (!theme.showGlobalWatermark) return null;
    return (
      <div className="watermark-text-stamp-container absolute inset-0 pointer-events-none z-50 overflow-hidden flex items-center justify-center">
        <div className="whitespace-nowrap font-black uppercase tracking-[1em] transform -rotate-[35deg]"
             style={{ 
               fontSize: `${theme.watermarkSize}rem`, 
               opacity: theme.watermarkOpacity, 
               color: theme.watermarkColor || (isDarkTheme ? '#ffffff' : '#000000') 
             }}>
          {theme.watermarkText}
        </div>
