      style={isMobile ? mobileStyle : desktopStyle}
      onMouseDown={stopFocusLoss}
    >
      <div className="flex items-center justify-center space-x-1 overflow-x-auto w-full max-w-full custom-scrollbar pb-1 lg:pb-0">
