          >
            <option value="">Font</option>
            {FONT_OPTIONS.map(f => <option key={f} value={f}>{f}</option>)}
          </select>
          <select 
            onChange={(e) => apply('fontSize', e.target.value)}
            className="bg-slate-50 text-[10px] lg:text-[11px] font-bold outline-none cursor-pointer p-1.5 lg:p-2 rounded-xl border border-slate-200"
            defaultValue="3"
          >
            <option value="1">S</option>
            <option value="3">M</option>
            <option value="5">L</option>
            <option value="7">XL</option>
          </select>
        </div>

        <div className={`flex items-center space-x-0.5 lg:space-x-1 ${!isMobile ? 'border-r border-slate-100 pr-3 mr-1' : ''}`}>
          <button onMouseDown={(e) => { e.preventDefault(); apply('bold'); }} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 font-black text-sm lg:text-lg" title="Bold">B</button>
          <button onMouseDown={(e) => { e.preventDefault(); apply('italic'); }} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 italic font-serif text-sm lg:text-lg" title="Italic">I</button>
