const EditableField = ({ value, onBlur, className, style }: any) => {
  const fieldRef = useRef<HTMLDivElement>(null);
  const isEditing = useRef(false);

  useEffect(() => {
    if (fieldRef.current && !isEditing.current) {
      fieldRef.current.innerHTML = value || '';
    }
  }, [value]);

  if (!onBlur) return <div className={className} style={style} dangerouslySetInnerHTML={{ __html: value }}></div>;

  return (
    <div 
      ref={fieldRef}
      contentEditable 
      suppressContentEditableWarning 
      onFocus={() => { isEditing.current = true; }}
      onInput={(e) => {
        const newHtml = e.currentTarget.innerHTML;
        if (newHtml !== value) {
          // Parent update can be triggered here if needed for live sync
        }
      }}
      onBlur={(e) => {
        isEditing.current = false;
        const newHtml = e.currentTarget.innerHTML;
        if (newHtml !== value) {
          onBlur(newHtml);
        }
      }}
      className={`${className} edit-highlight outline-none cursor-text p-1 rounded-sm transition-all focus:bg-blue-50/50 min-h-[1em]`}
      style={style}
    />
  );
};

