  const doc = new DOMParser().parseFromString(html, 'text/html');
  return doc.body.textContent || "";
};

/**
 * Professional Rich Text Toolbar with smooth animations.
 * Features a persistent presence with sliding transitions.
 */
const ProToolbar: React.FC<{ 
  position: { x: number, y: number } | null, 
  visible: boolean,
  onClose: () => void 
}> = ({ position, visible, onClose }) => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [showColorPicker, setShowColorPicker] = useState(false);
  const [activeColor, setActiveColor] = useState('#000000');

  useEffect(() => {
    const checkSize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', checkSize);
    return () => window.removeEventListener('resize', checkSize);
  }, []);

  const apply = (cmd: string, val?: string) => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0) return;

    document.execCommand(cmd, false, val);

    const anchor = selection.anchorNode;
    const editable = anchor?.parentElement?.closest('[contenteditable="true"]');
    if (editable) {
      editable.dispatchEvent(new Event('input', { bubbles: true }));
    }

    if (cmd === 'foreColor' && val) {
      setActiveColor(val);
      setShowColorPicker(false);
    }
  };

  const handleInsertImage = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e: any) => {
      const file = e.target.files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = (event) => {
          const base64 = event.target?.result as string;
          const imgHtml = `<img src="${base64}" style="max-width: 100%; height: auto; border-radius: 12px; margin: 20px 0; display: block; box-shadow: 0 10px 30px -10px rgba(0,0,0,0.1);" alt="Inserted asset" />`;
          document.execCommand('insertHTML', false, imgHtml);
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const stopFocusLoss = (e: React.MouseEvent) => {
    const target = e.target as HTMLElement;
    if (target.tagName !== 'SELECT' && target.tagName !== 'INPUT') {
      e.preventDefault();
    }
  };

  const desktopStyle: React.CSSProperties = {
    position: 'fixed',
    top: position ? position.y - 12 : 0,
    left: position ? position.x : 0,
    transform: `translate(-50%, ${visible ? '-100%' : '0%'}) scale(${visible ? 1 : 0.8})`,
    opacity: visible ? 1 : 0,
    pointerEvents: visible ? 'auto' : 'none',
    zIndex: 2000,
  };

  const mobileStyle: React.CSSProperties = {
    position: 'fixed',
    bottom: 'env(safe-area-inset-bottom, 0)',
    left: 0,
    right: 0,
    transform: `translateY(${visible ? '0%' : '100%'})`,
    opacity: visible ? 1 : 0,
    pointerEvents: visible ? 'auto' : 'none',
    zIndex: 2000,
    borderRadius: '24px 24px 0 0',
  };

  return (
    <div 
      className={`${isMobile ? 'bg-white shadow-[0_-20px_50px_rgba(0,0,0,0.15)] border-t border-slate-100 p-4 pb-8' : 'bg-white border border-slate-200 shadow-[0_30px_90px_-15px_rgba(0,0,0,0.3)] rounded-2xl p-2 origin-bottom'} flex flex-col items-center justify-center no-print transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)]`}
      style={isMobile ? mobileStyle : desktopStyle}
      onMouseDown={stopFocusLoss}
    >
      <div className="flex items-center justify-center space-x-1 overflow-x-auto w-full max-w-full custom-scrollbar pb-1 lg:pb-0">
        <div className={`flex items-center ${isMobile ? 'space-x-1' : 'border-r border-slate-100 pr-3 mr-1'}`}>
          <select 
            onChange={(e) => apply('fontName', e.target.value)}
            className="bg-slate-50 text-[10px] lg:text-[11px] font-bold outline-none cursor-pointer p-1.5 lg:p-2 rounded-xl border border-slate-200 w-16 lg:w-24"
          >
            <option value="">Font</option>
            {FONT_OPTIONS.map(f => <option key={f} value={f}>{f}</option>)}
          </select>
          <select 
            onChange={(e) => apply('fontSize', e.target.value)}
            className="bg-slate-50 text-[10px] lg:text-[11px] font-bold outline-none cursor-pointer p-1.5 lg:p-2 rounded-xl border border-slate-200"
            defaultValue="3"
          >
            <option value="1">S</option>
            <option value="3">M</option>
            <option value="5">L</option>
            <option value="7">XL</option>
          </select>
        </div>

        <div className={`flex items-center space-x-0.5 lg:space-x-1 ${!isMobile ? 'border-r border-slate-100 pr-3 mr-1' : ''}`}>
          <button onMouseDown={(e) => { e.preventDefault(); apply('bold'); }} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 font-black text-sm lg:text-lg">B</button>
          <button onMouseDown={(e) => { e.preventDefault(); apply('italic'); }} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 italic font-serif text-sm lg:text-lg">I</button>
          <button onMouseDown={(e) => { e.preventDefault(); apply('underline'); }} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 underline text-sm lg:text-lg">U</button>
          <button onMouseDown={(e) => { e.preventDefault(); apply('strikeThrough'); }} className="w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center hover:bg-slate-100 rounded-xl text-slate-900 line-through text-xs lg:text-base">S</button>
