  const doc = new DOMParser().parseFromString(html, 'text/html');
  return doc.body.textContent || "";
};

/**
 * Professional Rich Text Toolbar.
 * Refined positioning to prevent content obstruction.
 * Reimagined mobile color tools for better accessibility and visibility.
 */
const ProToolbar: React.FC<{ 
  position: { x: number, y: number } | null, 
  visible: boolean,
  onClose: () => void 
}> = ({ position, visible, onClose }) => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [showColorPicker, setShowColorPicker] = useState(false);
  const [activeColor, setActiveColor] = useState('#000000');

  useEffect(() => {
    const checkSize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', checkSize);
    return () => window.removeEventListener('resize', checkSize);
  }, []);

  const apply = (cmd: string, val?: string) => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0) return;

    document.execCommand(cmd, false, val);

    const anchor = selection.anchorNode;
    const editable = anchor?.parentElement?.closest('[contenteditable="true"]');
    if (editable) {
      editable.dispatchEvent(new Event('input', { bubbles: true }));
    }

    if (cmd === 'foreColor' && val) {
      setActiveColor(val);
      // Only auto-close on desktop; on mobile we might want to stay in color mode
      if (!isMobile) setShowColorPicker(false);
    }
  };

  const stopFocusLoss = (e: React.MouseEvent) => {
    const target = e.target as HTMLElement;
    if (target.tagName !== 'SELECT' && target.tagName !== 'INPUT' && !target.closest('button')) {
      e.preventDefault();
    }
  };

  // Fixed mobile colors for quick selection
  const COLORS = ['#000000', '#ef4444', '#22c55e', '#3b82f6', '#f59e0b', '#8b5cf6', '#ec4899', '#ffffff'];

  const desktopStyle: React.CSSProperties = {
    position: 'fixed',
    top: position ? Math.max(80, position.y - 12) : 0, // Prevent covering header
    left: position ? Math.max(100, Math.min(window.innerWidth - 100, position.x)) : 0, // Prevent edge overflow
    transform: `translate(-50%, ${visible ? '-100%' : '0%'}) scale(${visible ? 1 : 0.8})`,
    opacity: visible ? 1 : 0,
    pointerEvents: visible ? 'auto' : 'none',
    zIndex: 2000,
  };

  const mobileStyle: React.CSSProperties = {
    position: 'fixed',
    bottom: 'env(safe-area-inset-bottom, 0)',
    left: 0,
    right: 0,
    transform: `translateY(${visible ? '0%' : '100%'})`,
    opacity: visible ? 1 : 0,
    pointerEvents: visible ? 'auto' : 'none',
    zIndex: 2000,
    borderRadius: '24px 24px 0 0',
  };

  return (
    <div 
      className={`${isMobile ? 'bg-white shadow-[0_-10px_40px_rgba(0,0,0,0.2)] border-t border-slate-100 p-4 pb-8' : 'bg-white border border-slate-200 shadow-[0_30px_90px_-15px_rgba(0,0,0,0.3)] rounded-2xl p-2 origin-bottom'} flex flex-col items-center justify-center no-print transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)]`}
      style={isMobile ? mobileStyle : desktopStyle}
      onMouseDown={stopFocusLoss}
    >
      {/* Mobile-only Color Palette Row: Always visible when toolbar is out */}
      {isMobile && (
