              </div>
            </div>

            <button onClick={handleExportPDF} className="w-full py-6 bg-blue-600 text-white rounded-2xl font-black text-sm uppercase tracking-[0.4em] shadow-xl hover:bg-blue-700 transition-all">Generate PDF Archive</button>
            <button onClick={handleExportPPTX} className="w-full py-6 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase tracking-[0.4em] hover:bg-black transition-all">Professional PPTX</button>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-100 selection:bg-blue-600 selection:text-white overflow-hidden font-sans">
      {step === AppStep.DASHBOARD && renderDashboard()}
      {step === AppStep.EDITOR && renderEditor()}
    </div>
  );
};

export default App;
